11	 *
12	 * Fuzzing harness for HDF5 object-header visiting and link iteration:
13	 *   H5Oopen, H5Oget_info3, H5Ovisit3, H5Oclose, H5Literate2, H5Lget_val
14	 *
15	 * Strategy:
16	 *  1. Write fuzz data to a temp file and open it read-only.
17	 *  2. Retrieve info on the root object via H5Oget_info3.
18	 *  3. Iterate links in the root group via H5Literate2 (name and creation-order
19	 *     indices, both directions).  For each soft link call H5Lget_val; for hard
20	 *     and soft links open the target with H5Oopen + H5Oget_info3 + H5Oclose.
21	 *  4. Recursively visit every reachable object via H5Ovisit3 (two index types).
22	 *     Inside the visitor, open each visited object by path and read its info.
23	 */
24	
25	#include "hdf5.h"
26	
27	#include <stdint.h>
28	#include <stdio.h>
29	#include <stdlib.h>
30	#include <string.h>
31	#include <unistd.h>
32	
33	/* Hard cap on callbacks to avoid spending forever on highly-connected graphs */
34	#define MAX_CB_CALLS 2000
35	
36	/* Soft-link value buffer cap – large enough to be interesting, small enough to
37	 * avoid gigantic allocations on crafted val_size fields.                      */
38	#define MAX_LVAL_BUF 65536
39	
40	/* -------------------------------------------------------------------------
41	 * Shared state threaded through callbacks
42	 * ---------------------------------------------------------------------- */
43	typedef struct {
44	    hid_t file_id;   /* The open file – used to re-open objects by path */
45	    int   calls;     /* Running callback count (rate-limiting guard)     */
46	} cb_state_t;
47	
48	/* -------------------------------------------------------------------------
49	 * H5Ovisit3 callback
50	 *
51	 *  obj  – the starting object passed to H5Ovisit3 (stays constant)
52	 *  name – path from starting object to the currently-visited object
53	 *  info – pre-filled info struct for the current object
54	 * ---------------------------------------------------------------------- */
55	static herr_t
56	obj_visit_cb(hid_t obj, const char *name, const H5O_info2_t *info,
57	             void *op_data)
58	{
59	    cb_state_t *st = (cb_state_t *)op_data;
60	    if (st->calls++ >= MAX_CB_CALLS)
61	        return 1; /* non-zero stops iteration */
62	
63	    /* Consume all info fields so the parser path is exercised */
64	    (void)info->type;
65	    (void)info->rc;
66	    (void)info->num_attrs;
67	    (void)info->atime;
68	    (void)info->mtime;
69	
70	    /* "." is the starting object itself – skip the re-open to avoid an
71	     * open-on-self cycle, but the info was already consumed above.     */
72	    if (!name || name[0] == '\0' || strcmp(name, ".") == 0)
73	        return 0;
74	
75	    /* Open the visited object by path relative to the starting object,
76	     * fetch its info independently, then close it.  This exercises the
77	     * object-header parser on the same header via a different code path. */
78	    hid_t child = H5Oopen(obj, name, H5P_DEFAULT);
79	    if (child != H5I_INVALID_HID) {
80	        H5O_info2_t ci;
81	        H5Oget_info3(child, &ci, H5O_INFO_ALL);
82	        H5Oclose(child);
83	    }
84	
85	    return 0;
86	}
87	
88	/* -------------------------------------------------------------------------
89	 * H5Literate2 callback
90	 *
91	 *  group – the group being iterated
92	 *  name  – link name within that group
93	 *  info  – link metadata
94	 * ---------------------------------------------------------------------- */
95	static herr_t
96	link_iter_cb(hid_t group, const char *name, const H5L_info2_t *info,
97	             void *op_data)
98	{
99	    cb_state_t *st = (cb_state_t *)op_data;
100	    if (st->calls++ >= MAX_CB_CALLS)
101	        return 1;
102	
103	    /* Consume link metadata */
104	    (void)info->corder_valid;
105	    (void)info->corder;
106	    (void)info->cset;
107	
108	    /* For soft links: retrieve the link value (target path string).
109	     * val_size comes from the fuzzed file – cap allocation defensively. */
110	    if (info->type == H5L_TYPE_SOFT) {
111	        size_t vsz = info->u.val_size;
112	        if (vsz > 0 && vsz <= MAX_LVAL_BUF) {
113	            char *buf = (char *)malloc(vsz + 1);
114	            if (buf) {
115	                buf[vsz] = '\0';
116	                H5Lget_val(group, name, buf, vsz + 1, H5P_DEFAULT);
117	                free(buf);
118	            }
119	        }
120	    }
121	
122	    /* Open the target object for hard and soft links.
123	     * Skip external links to avoid touching the filesystem beyond /tmp.  */
124	    if (info->type == H5L_TYPE_HARD || info->type == H5L_TYPE_SOFT) {
125	        hid_t obj = H5Oopen(group, name, H5P_DEFAULT);
126	        if (obj != H5I_INVALID_HID) {
127	            H5O_info2_t oinfo;
128	            H5Oget_info3(obj, &oinfo, H5O_INFO_ALL);
129	            H5Oclose(obj);
130	        }
131	    }
132	
133	    return 0;
134	}
135	
136	/* -------------------------------------------------------------------------
137	 * Fuzz entry point
138	 * ---------------------------------------------------------------------- */
139	int LLVMFuzzerTestOneInput(const uint8_t *data, size_t size)
140	{
141	    char filename[256];
142	
143	    /* Suppress HDF5 error output – it's noisy and not useful for fuzzing */
144	    H5Eset_auto2(H5E_DEFAULT, NULL, NULL);
145	
146	    snprintf(filename, sizeof(filename), "/tmp/h5_obj_visit_%d", getpid());
147	
148	    FILE *fp = fopen(filename, "wb");
149	    if (!fp)
150	        return 0;
151	    fwrite(data, size, 1, fp);
152	    fclose(fp);
153	
154	    /* Open read-only: we must not inadvertently mutate file metadata and
155	     * thereby introduce harness-side state that obscures real bugs.      */
156	    hid_t file_id = H5Fopen(filename, H5F_ACC_RDONLY, H5P_DEFAULT);
157	    if (file_id == H5I_INVALID_HID) {
158	        unlink(filename);
159	        return 0;
160	    }
161	
162	    cb_state_t state = {file_id, 0};
163	
164	    /* ---- 1. Root-object info ---------------------------------------- */
165	    H5O_info2_t root_info;
166	    H5Oget_info3(file_id, &root_info, H5O_INFO_ALL);
167	
168	    /* ---- 2. Link iteration (name index, native order) ---------------- */
169	    hsize_t idx = 0;
170	    H5Literate2(file_id, H5_INDEX_NAME, H5_ITER_NATIVE, &idx,
171	                link_iter_cb, &state);
172	
173	    /* ---- 3. Link iteration (creation-order index, increasing) -------- */
174	    idx = 0;
175	    H5Literate2(file_id, H5_INDEX_CRT_ORDER, H5_ITER_INC, &idx,
176	                link_iter_cb, &state);
177	
178	    /* ---- 4. Link iteration (name index, decreasing) ------------------ */
179	    idx = 0;
180	    H5Literate2(file_id, H5_INDEX_NAME, H5_ITER_DEC, &idx,
181	                link_iter_cb, &state);
182	
183	    /* ---- 5. Object visit (name index) -------------------------------- */
184	    state.calls = 0;
185	    H5Ovisit3(file_id, H5_INDEX_NAME, H5_ITER_NATIVE,
186	               obj_visit_cb, &state, H5O_INFO_ALL);
187	
188	    /* ---- 6. Object visit (creation-order index, increasing) ---------- */
189	    state.calls = 0;
190	    H5Ovisit3(file_id, H5_INDEX_CRT_ORDER, H5_ITER_INC,
191	               obj_visit_cb, &state, H5O_INFO_ALL);
192	
193	    H5Fclose(file_id);
194	    unlink(filename);
195	    return 0;
196	}
